patch:
diff --git a/llvm/lib/Transforms/Scalar/GVNSink.cpp b/llvm/lib/Transforms/Scalar/GVNSink.cpp
index 2058df33ea33..e6f0c8e75cfe 100644
--- a/llvm/lib/Transforms/Scalar/GVNSink.cpp
+++ b/llvm/lib/Transforms/Scalar/GVNSink.cpp
@@ -801,6 +801,12 @@ void GVNSink::sinkLastInstruction(ArrayRef<BasicBlock *> Blocks,
   for (BasicBlock *BB : Blocks)
     Insts.push_back(BB->getTerminator()->getPrevNonDebugInstruction());
   Instruction *I0 = Insts.front();
+  // Don't sink inline assembly calls as they cannot be used in PHI nodes
+  if (CallBase *CB = dyn_cast<CallBase>(I0)) {
+    if (CB->isInlineAsm())
+      return;
+  }
+

   SmallVector<Value *, 4> NewOperands;
   for (unsigned O = 0, E = I0->getNumOperands(); O != E; ++O) {

